// Process competitor data and generate intelligence
const competitors = $input.all();

const intel = competitors.map(c => {
  const comp = c.json;
  return {
    name: comp.name || 'unknown',
    platform: comp.platform || 'instagram',
    price: comp.price || 0,
    followers: comp.followers || 0,
    last_content_date: comp.last_content_date || '',
    content_frequency: comp.content_frequency || 'unknown',
    engagement_rate: comp.engagement_rate || 0,
    offer_type: comp.offer_type || '',
    last_move: comp.last_move || '',
    threat_level: comp.threat_level || 'low'
  };
});

// Our positioning
const ourPrice = 350;
const avgCompPrice = intel.length > 0 
  ? Math.round(intel.reduce((s, c) => s + c.price, 0) / intel.length) 
  : 0;
const priceAdvantage = avgCompPrice > 0 ? Math.round((1 - ourPrice / avgCompPrice) * 100) : 0;

// Threat analysis
const highThreats = intel.filter(c => c.threat_level === 'high');
const newMoves = intel.filter(c => {
  if (!c.last_content_date) return false;
  const lastDate = new Date(c.last_content_date);
  return (Date.now() - lastDate) < 48 * 60 * 60 * 1000; // last 48 hours
});

let alert = '';
if (highThreats.length > 0) {
  alert = `🔴 ${highThreats.length} منافسين بتهديد عالي: ${highThreats.map(h => h.name).join(', ')}`;
} else if (newMoves.length > 0) {
  alert = `🟡 ${newMoves.length} منافسين نشطين آخر 48 ساعة`;
} else {
  alert = '🟢 لا تحركات ملحوظة';
}

return {
  json: {
    competitors: intel,
    analysis: {
      total_tracked: intel.length,
      our_price: ourPrice,
      avg_competitor_price: avgCompPrice,
      price_advantage_pct: priceAdvantage,
      high_threats: highThreats.length,
      recent_moves: newMoves.length,
      alert
    }
  }
};

