const response = $input.item.json;
const analysis = $('Analyze Competitors').item.json.analysis;
let claudeIntel;

try {
  const content = response.content?.[0]?.text || '{}';
  let jsonStr = content;
  if (jsonStr.includes('```json')) jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
  else if (jsonStr.includes('```')) jsonStr = jsonStr.split('```')[1].split('```')[0].trim();
  claudeIntel = JSON.parse(jsonStr);
} catch (e) {
  claudeIntel = {
    threats: ['خطأ في التحليل'],
    opportunities: [],
    recommended_moves: ['مراجعة يدوية'],
    competitive_edge: 'غير متاح'
  };
}

return {
  json: {
    ...analysis,
    intel: claudeIntel
  }
};

